import{_ as e,c as a,o as r,ah as t}from"./chunks/framework.C_vVbgOK.js";const u=JSON.parse('{"title":"Аналіз предметної області 🔎","description":"","frontmatter":{},"headers":[],"relativePath":"requirements/state-of-the-art.md","filePath":"requirements/state-of-the-art.md"}'),l={name:"requirements/state-of-the-art.md"},n=t('<h1 id="аналіз-предметноі-області-🔎" tabindex="-1">Аналіз предметної області 🔎 <a class="header-anchor" href="#аналіз-предметноі-області-🔎" aria-label="Permalink to &quot;Аналіз предметної області 🔎&quot;">​</a></h1><h2 id="📖-вступ" tabindex="-1">📖 Вступ <a class="header-anchor" href="#📖-вступ" aria-label="Permalink to &quot;📖 Вступ&quot;">​</a></h2><p>Цей документ містить основні визначення, які допоможуть детально проаналізувати предметну область проєкту. А також тут розглянуто стадії циклу та методики розробки програмного забезпечення. На основні зібраних даних створено порівняльну характеристику засобів вирішення завдання і таблицю, яка допомагає зорієнтуватися у функціональних якостях розгялнутих сервісів.</p><h3 id="📑-зміст" tabindex="-1">📑 Зміст: <a class="header-anchor" href="#📑-зміст" aria-label="Permalink to &quot;📑 Зміст:&quot;">​</a></h3><ul><li><a href="#📝-основні-визначення">Основні визначення</a>, які дозволять користувачу зрозуміти структуру систем управління проєктами;</li><li><a href="#💡-підходи-та-способи-вирішення-завдання">Підходи та способи вирішення завдання</a> в області систем управління проєктами;</li><li><a href="#⚖️-порівняльна-характеристика-наявних-засобів-вирішення-завдання">Порівняльна характеристика наявних засобів вирішення завдання</a>, яка містить детальний розбір переваг і недоліків сервісів відповідно до критеріїв FURPS;</li><li><a href="#🎯-висновки">Висновки</a>;</li><li><a href="#🔗-посилання">Посилання</a>.</li></ul><h2 id="📝-основні-визначення" tabindex="-1">📝 Основні визначення <a class="header-anchor" href="#📝-основні-визначення" aria-label="Permalink to &quot;📝 Основні визначення&quot;">​</a></h2><p><a href="https://uk.wikipedia.org/wiki/%D0%9F%D1%80%D0%BE%D1%94%D0%BA%D1%82" target="_blank" rel="noreferrer">Проєкт</a> — сукупність моделей, проєктна конструкторська документація, яка містить проєктні рішення і дає повне уявлення про будову розроблюваного виробу, процесу або організації.</p><p><a href="https://pmb.com.ua/uk/slovar-terminov/sistema-upravleniya-proektom-project-management-system-instrument/" target="_blank" rel="noreferrer">Система управління проектами</a> — Сукупність процесів, інструментів, методів, методологій, ресурсів і процедур з управління проєктом. Система документується в плані управління проєктами, і її зміст може відрізнятися в залежності від галузі застосування, організаційного впливу, складності проєкту і доступності наявних систем.</p><p><a href="https://pmb.com.ua/uk/slovar-terminov/zhiznennyj-tsikl-proekta-project-life-cycle/" target="_blank" rel="noreferrer">Життєвий цикл проєкту</a> — набір, зазвичай, послідовних фаз проєкту, кількість і склад яких визначається потребами управління проєктом організації або організаціями, які беруть участь в проєкті. Життєвий цикл можна документувати за допомогою методології.</p><p><a href="https://dtkt.ua/dictionary/p/7447-programne-zabezpecennya" target="_blank" rel="noreferrer">Програмне забезпечення</a> — сукупність програм, необхідних для виконання всіх основних і додаткових функцій системи (компонента), які зберігаються в пам&#39;яті та/або в програмувальних електронних пристроях, що входять до складу цієї системи (компонента), а також програм на зовнішніх носіях і програмної документації.</p><p><a href="https://qalearning.com.ua/theory/lectures/material/requirements-testing-methods-equivalence/" target="_blank" rel="noreferrer">Вимоги до програмного забезпечення</a> — сукупність тверджень щодо атрибутів, властивостей, або якостей програмної системи, що підлягає реалізації.</p><p><a href="https://uk.wikipedia.org/wiki/%D0%90%D1%80%D1%82%D0%B5%D1%84%D0%B0%D0%BA%D1%82_(UML)" target="_blank" rel="noreferrer">Артефакт</a> — окремий шмат інформації, що використовується чи з&#39;являється в процесі розробки програмного забезпечення. Це може бути файл з кодом, модель, частина документації, чи повідомлення електронної пошти або навіть нотатка, приклеєна до монітора.</p><p><a href="https://worksection.com/ua/blog/agile.html" target="_blank" rel="noreferrer">Agile Model</a> —  ітеративна модель розроблення, у якій програмне забезпечення створюють інкрементально від самого початку проєкту, на відміну від каскадних моделей, де код доставляють наприкінці робочого циклу.</p><p><a href="https://career.softserveinc.com/uk-ua/stories/what-is-scrum-methodology" target="_blank" rel="noreferrer">Scrum</a> — це специфічна структура в рамках ширших методів Agile. Це потужний інструмент для керування складними проєктами зі змінними вимогами, що пропонує численні переваги у співпраці, гнучкості та задоволеності клієнтів.</p><p><a href="https://www.maxzosim.com/boehms-spiral-model/" target="_blank" rel="noreferrer">Spiral Model</a> — це ризик-орієнтована модель процесу розробки програмного забезпечення. Спираючись на унікальні моделі ризиків конкретного проекту, спіральна модель спрямовує команду на прийняття елементів однієї або декількох моделей процесу, таких як інкрементне, водоспадне або еволюційне прототипування.</p><p><a href="https://itwiki.dev/qa/dev-methodologies/incremental-development-model" target="_blank" rel="noreferrer">Incremental Model</a> — модель життєвого циклу розробки, в якій проект поділено на серію прирощень, кожна з яких додає частину функціональності у загальних вимогах проекту.</p><p><a href="https://www.ukraine.com.ua/blog/interesting/chto-takoe-kanban.html" target="_blank" rel="noreferrer">Kanban</a> — це гнучкий метод еволюційного управління змінами в проектах. Це означає, що існуючий процес вдосконалюється невеликими кроками (еволюційно). У підсумку, роблячи багато невеликих змін (а не одне велике), ми зменшуємо ризики для всього проекту в цілому.</p><p><a href="https://web-promo.ua/ua/blog/kanban-sho-ce-take-i-chim-vin-bude-korisnim-marketologam/" target="_blank" rel="noreferrer">Kanban-board</a> — це інструмент управління проєктами, візуалізація завдань, які необхідно виконати різним працівникам/підрозділам вашої компанії.</p><h2 id="💡-підходи-та-способи-вирішення-завдання" tabindex="-1">💡 Підходи та способи вирішення завдання <a class="header-anchor" href="#💡-підходи-та-способи-вирішення-завдання" aria-label="Permalink to &quot;💡 Підходи та способи вирішення завдання&quot;">​</a></h2><p>Розробка програмного забезпечення зазвичай проходить через певні основні етапи. Хоча підходи можуть відрізнятися деталями, загальний принцип залишається незмінним. Основні стадії створення програмного продукту включають:</p><ul><li><p>Аналіз вимог – дослідження ідеї та очікувань замовника, аналіз ринку, конкурентів та потенційної аудиторії. На цьому етапі формується розуміння ключових функцій майбутньої системи.</p></li><li><p>Проєктування – розробка архітектури, створення прототипів і планування завдань. Формується загальна логіка продукту, визначається його структура та дизайн.</p></li><li><p>Розробка – програмування та інтеграція всіх компонентів. Дизайнери працюють над інтерфейсом і UX, а розробники перетворюють концепцію в робочий програмний продукт.</p></li><li><p>Документування – створення технічної документації для розробників і супровідних матеріалів для користувачів, що описують функціонал і принципи роботи програми.</p></li><li><p>Тестування – перевірка працездатності та надійності системи, усунення можливих помилок і виявлення недоліків перед впровадженням.</p></li><li><p>Впровадження та підтримка – розгортання готового продукту, забезпечення його подальшої роботи та надання технічної підтримки для користувачів.</p></li></ul><p>Ці етапи є фундаментом у процесі створення програмного забезпечення, забезпечуючи якісний результат та відповідність очікуванням користувачів.</p><h3 id="🚰-методологія-waterfall" tabindex="-1">🚰 Методологія Waterfall <a class="header-anchor" href="#🚰-методологія-waterfall" aria-label="Permalink to &quot;🚰 Методологія Waterfall&quot;">​</a></h3><p>Каскадний підхід, відомий як методологія ” Waterfall “, є структурованим методом управління проектами, де процес проходить через чітко визначені фази. Кожна з цих фаз має бути завершена до початку наступної. Класична модель Waterfall складається з наступних етапів: аналіз вимог, проектування системи, реалізація, тестування, розгортання та обслуговування. Така модель роботи дозволяє точно планувати і контролювати хід проекту.</p><p>Каскадна модель роботи базується на припущенні, що всі вимоги відомі на початку проекту і не зазнають суттєвих змін під час його виконання. Це дає можливість створювати детальний графік і точно управляти ресурсами. Методологія Waterfall особливо корисна в інженерних, будівельних і виробничих проектах, де зміни під час виконання можуть призвести до високих витрат.<a href="https://flexi-project.com/uk/%D1%89%D0%BE-%D1%82%D0%B0%D0%BA%D0%B5-%D0%BC%D0%B5%D1%82%D0%BE%D0%B4%D0%BE%D0%BB%D0%BE%D0%B3%D1%96%D1%8F-waterfall-%D1%96-%D1%8F%D0%BA-%D0%B2%D0%BE%D0%BD%D0%B0-%D0%BF%D1%80%D0%B0%D1%86%D1%8E%D1%94/" target="_blank" rel="noreferrer">[1]</a></p><p align="center"><img src="https://miro.medium.com/v2/resize:fit:640/format:webp/1*tGKCSfTfV8E8t4atqrLE4A.png" alt="Waterfall"></p><p align="center">Схема Waterfall</p><h3 id="⚡-методологія-agile" tabindex="-1">⚡ Методологія Agile <a class="header-anchor" href="#⚡-методологія-agile" aria-label="Permalink to &quot;⚡ Методологія Agile&quot;">​</a></h3><p>Agile методологія розробки програмного забезпечення - це підхід до управління проектами, що базується на ітеративному та інкрементальному процесі розробки. Цей підхід став дуже популярним серед IT-компаній через свою гнучкість, можливість адаптації до змін і спрощення комунікації в команді. У цій статті ми розглянемо основні принципи та переваги Agile методології.</p><p>У межах Agile існує кілька методологій, які допомагають реалізувати ці принципи та цінності, такі як Scrum, Kanban, Extreme Programming (XP) та інші. Кожна з цих методологій має свої особливості та підходи до організації робочих процесів.<a href="https://it-rating.ua/agile-metodologiya-rozrobki-programnogo-zabezpechennya" target="_blank" rel="noreferrer">[2]</a></p><p align="center"><img src="https://i0.wp.com/indevlab.com/wp-content/uploads/2020/05/vnutr.png?" alt="Agile"></p><p align="center">Схема Agile</p><h3 id="📊-методологія-kanban" tabindex="-1">📊 Методологія Kanban <a class="header-anchor" href="#📊-методологія-kanban" aria-label="Permalink to &quot;📊 Методологія Kanban&quot;">​</a></h3><p>Канбан — це метод для розробки продуктів, який допомагає налагодити поточні процеси і перевантажити команду. Незавершені завдання не простоюють і потоком рухаються ланцюжком створення продукту або його підтримки. В основі kanban — Agile та гнучка розробка.</p><p>Kanban — це насамперед візуалізація. Для візуалізації використовують дошку та набір різнокольорових карток. Один колір — один виконавець чи процес. Усі учасники команди будь-коли можуть перевірити стан будь-якого завдання.<a href="https://laba.ua/blog/1529-kanban-principy-i-polza" target="_blank" rel="noreferrer">[3]</a></p><p align="center"><img src="https://kanbanize.com/wp-content/uploads/website-images/kanban-resources/Kanban_board-elements.png" alt="Kanban"></p><p align="center">Схема Kanban</p><h3 id="🍃-методологія-lean" tabindex="-1">🍃 Методологія Lean <a class="header-anchor" href="#🍃-методологія-lean" aria-label="Permalink to &quot;🍃 Методологія Lean&quot;">​</a></h3><p>LEAN – це система управління, філософія, інструментарій, що має на меті максимізувати цінність для споживача та мінімізувати витрати для компанії.<a href="https://lvbs.com.ua/news/yak-lean-metodologiya-dopomagaye-biznesu-v-umovah-oshhadlyvosti/" target="_blank" rel="noreferrer">[4.1]</a></p><p>Мислення за принципом Lean, або ж ощадливе мислення, фокусується вже не на оптимізації керуючої вертикалі — окремих технологій, активів і вертикальних відділів. Натомість ми вчимося оптимізувати потік продуктів і послуг крізь усі потоки створення цінності, що проходять по горизонталі крізь технології, активи й відділи напряму до клієнтів.<a href="https://brainrain.com.ua/uk/chto-takoe-lean/" target="_blank" rel="noreferrer">[4.2]</a></p><p align="center"><img src="https://cdn.create.vista.com/api/media/small/372737326/stock-vector-lean-software-development-methodology-diagram-scheme-infographics-circles-united-title" alt="Lean"></p><p align="center">Схема Lean</p><h3 id="🏉-методологія-scrum" tabindex="-1">🏉 Методологія Scrum <a class="header-anchor" href="#🏉-методологія-scrum" aria-label="Permalink to &quot;🏉 Методологія Scrum&quot;">​</a></h3><p>Фреймворк Scrum забезпечує структуру методології. Вона складається з ролей, подій та артефактів, які забезпечують прозорість, перевірку та адаптацію протягом усього проекту. Основні функції включають Scrum Master, Product Owner і Team Development, а події на кшталт Daily Scrum, Sprint Planning, Sprint Review і Sprint Retrospective тримають проект у руслі.</p><p>Модель Scrum керується принципами прозорості, перевірки та адаптації. Прозорість гарантує, що всі зацікавлені сторони мають спільне розуміння розвитку проєкту. Перевірка передбачає регулярне оцінювання продукту та процесів для визначення областей, які слід покращити. Адаптація означає внесення змін на основі результатів перевірки для оптимізації результату проєкту.<a href="https://career.softserveinc.com/uk-ua/stories/what-is-scrum-methodology" target="_blank" rel="noreferrer">[5]</a></p><p align="center"><img src="https://career.softserveinc.com/uploads/stories/what-is-scrum-methodology/scrum-framework.jpg?1695041930286" alt="Scrum"></p><p align="center">Схема Scrum</p><h3 id="📈-методологія-incremental" tabindex="-1">📈 Методологія Incremental <a class="header-anchor" href="#📈-методологія-incremental" aria-label="Permalink to &quot;📈 Методологія Incremental&quot;">​</a></h3><p>Інкрементний процес передбачає поетапну розробку програмного забезпечення, коли його компоненти постачаються частинами. Кожен інкремент містить завершений набір функцій, які повністю реалізовані та протестовані.</p><p>Наприклад, у разі створення інтернет-магазину на початковому етапі можна реалізувати оплату лише кредитними та дебетовими картками. У наступному оновленні можна додати підтримку оплати через електронні гаманці.<a href="https://medium.com/@ashutoshagrawal1010/agile-methodology-incremental-and-iterative-way-of-development-a6614116ae68" target="_blank" rel="noreferrer">[6]</a></p><p align="center"><img src="https://newline.tech/wp-content/uploads/2019/06/Incremental-model-1.jpg" alt="Incremental"></p><p align="center">Схема Incremental</p><h3 id="🔄-методологія-iterative" tabindex="-1">🔄 Методологія Iterative <a class="header-anchor" href="#🔄-методологія-iterative" aria-label="Permalink to &quot;🔄 Методологія Iterative&quot;">​</a></h3><p>Ітеративний процес передбачає поступове вдосконалення системи через послідовні оновлення. Розробницька команда створює початкову версію продукту, заздалегідь знаючи, що деякі його частини будуть неповними. Далі ці частини покроково допрацьовуються, доки продукт не досягне задовільного рівня. Під час кожної ітерації враховуються відгуки користувачів, а програмне забезпечення покращується завдяки деталізації та розширенню функціональності.</p><p>Наприклад, розглянемо пошукову систему на сайті. У першій ітерації може бути реалізовано простий пошук. У наступному оновленні можна додати розширені критерії пошуку.<a href="https://medium.com/@ashutoshagrawal1010/agile-methodology-incremental-and-iterative-way-of-development-a6614116ae68" target="_blank" rel="noreferrer">[7]</a></p><p align="center"><img src="https://radiant.digital/wp-content/uploads/2021/11/What-is-interative-Design_1-1024x677.png" alt="Iterative"></p><p align="center">Схема Iterative</p><h3 id="🌀-методологія-spiral" tabindex="-1">🌀 Методологія Spiral <a class="header-anchor" href="#🌀-методологія-spiral" aria-label="Permalink to &quot;🌀 Методологія Spiral&quot;">​</a></h3><p>Спіральна модель є еволюцією традиційних підходів до розробки програмного забезпечення, таких як водоспадна модель. Вона поєднує ітеративність з послідовним аналізом ризиків на кожному етапі проекту. Спіральна модель ділить процес розробки на кілька циклів, кожен з яких складається з чотирьох фаз: визначення цілей, аналіз ризиків, розробка та планування наступного циклу.</p><p>Основна ідея спіральної моделі полягає в тому, що кожен новий цикл дозволяє команді вчитися на досвіді попереднього і приймати більш обґрунтовані рішення на наступному етапі. Це забезпечує високу ступінь адаптивності та дозволяє ефективно управляти ризиками проекту.<a href="https://skalar.ua/ua/methodology/spiral" target="_blank" rel="noreferrer">[8]</a></p><p align="center"><img src="https://techreceptives.com/tr_website/static/src/images/company/development_methodology/spiral-methodology.png" alt="Spiral"></p><p align="center">Схема Spiral</p><h3 id="🔺-методологія-v-model" tabindex="-1">🔺 Методологія V-Model <a class="header-anchor" href="#🔺-методологія-v-model" aria-label="Permalink to &quot;🔺 Методологія V-Model&quot;">​</a></h3><p>V-model - це життєвий цикл розроблення програмного забезпечення, який являє собою уточнення класичної водоспадної моделі.Перевагами цієї моделі є якість, відповідність стандартам і фіксовані терміни та бюджет на кожному етапі.</p><p>У V-моделі розробка відбувається у формі літери &quot;V&quot;, що зустрічається - розробка і тестування продукту відбуваються паралельно, а кожен етап тестування спрямований на перевірку відповідного етапу розробки.<a href="https://skalar.ua/ua/methodology/v-model" target="_blank" rel="noreferrer">[9]</a></p><p align="center"><img src="https://blog.kakaocdn.net/dn/dHS4K6/btqYn55cRXq/FrGWyavnMk5yk70Ks1HSaK/img.png" alt="V-Model"></p><p align="center">Схема V-Model</p><h3 id="🔁-методологія-devops" tabindex="-1">🔁 Методологія DevOps <a class="header-anchor" href="#🔁-методологія-devops" aria-label="Permalink to &quot;🔁 Методологія DevOps&quot;">​</a></h3><p>DevOps — це методологія або культурна філософія, набір практик, що поєднує розробку ПЗ (Dev) та ІТ-операції (Ops). Основна мета DevOps — скоротити цикл розробки ПЗ і подбати про безперервне доставлення програмних компонентів на кінцеве програмне середовище.<a href="https://dou.ua/lenta/articles/devops-engineer-career/" target="_blank" rel="noreferrer">[10.1]</a></p><p>Завдяки цьому підходу суттєво збільшується швидкість розробки, скорочуються проміжки між релізами, підвищується якість, надійність і безпека продуктів, а також забезпечується високе масштабування та організована робота команди.<a href="https://wezom.com.ua/ua/blog/chto-takoe-devops" target="_blank" rel="noreferrer">[10.2]</a></p><p align="center"><img src="https://habrastorage.org/getpro/habr/upload_files/3a1/8d5/e20/3a18d5e200fd9052aa42ab9378846d7e.png" alt="DevOps"></p><p align="center">Схема DevOps</p><h3 id="🚀-методологія-rad" tabindex="-1">🚀 Методологія RAD <a class="header-anchor" href="#🚀-методологія-rad" aria-label="Permalink to &quot;🚀 Методологія RAD&quot;">​</a></h3><p>Rapid Application Development (RAD) - це гнучка методологія розробки програмного забезпечення, яка акцентує увагу на швидкому створенні прототипів та ітеративному удосконаленні продукту. RAD розроблена для скорочення часу розробки та спрощення процесу впровадження змін, не жертвуючи при цьому якістю кінцевого продукту.</p><p>Методологія RAD складається з чотирьох ключових компонентів: вимоги, прототипування, швидка ітерація та співпраця. Команди, які використовують RAD, активно взаємодіють з замовниками та користувачами, щоб точно визначити вимоги, і на їх основі створюють робочі прототипи. Це дозволяє швидко вносити зміни та адаптуватися до нових потреб, роблячи процес розробки більш гнучким та відгуковим.<a href="https://skalar.ua/ua/methodology/rad" target="_blank" rel="noreferrer">[11]</a></p><p align="center"><img src="https://maybe.works/media/blogs/rapid-application-development-rad/1100x600.jpg" alt="RAD"></p><p align="center">Схема RAD</p><h3 id="🐳-методологія-mvc" tabindex="-1">🐳 Методологія MVC <a class="header-anchor" href="#🐳-методологія-mvc" aria-label="Permalink to &quot;🐳 Методологія MVC&quot;">​</a></h3><p>MVC (Model-View-Controller) — це архітектурний шаблон для розробки програмного забезпечення, який допомагає розділити програму на три основні частини.</p><p>Модель відповідає за обробку даних та бізнес-логіку програми. Вона зберігає інформацію і визначає, як ця інформація обробляється і змінюється. Вигляд відповідає за відображення даних користувачу. Він представляє інформацію з Моделі у зручному для користувача вигляді.Контролер взаємодіє з користувачем і відправляє команди до Моделі та Вигляду. Він контролює потік інформації між Моделлю і Виглядом та реагує на дії користувача.<a href="https://blog.ithillel.ua/articles/building-dynamic-web-applications-using-mvc" target="_blank" rel="noreferrer">[12]</a></p><p align="center"><img src="https://cdn.codegym.cc/images/article/b07930de-1eaf-4c34-978d-c74438052706/800.webp" alt="MVC"></p><p align="center">Схема MVC</p><h3 id="🔄-методологія-ci-cd" tabindex="-1">🔄 Методологія CI/CD <a class="header-anchor" href="#🔄-методологія-ci-cd" aria-label="Permalink to &quot;🔄 Методологія CI/CD&quot;">​</a></h3><p>Безперервна інтеграція (Continuous Integration, CI) і безперервне постачання (Continuous Delivery, CD) є культурою, набором принципів і практик, які дозволяють розробникам частіше і надійніше розгортати зміни програмного забезпечення. Обидва терміни дуже тісно пов’язані з професією DevOps і є основними термінами їх еволюції.</p><p>Основними інструментами для реалізації CI/CD можуть бути: GitLab, Docker, Jenkins, Maven, Ansible, Kubernetes і т.д. Безперечно такі методи забезпечуть оперативність виведення нового функціоналу продукту. Як правило, це лічені дні чи тижні. У той же час, при класичному підході до розробки клієнтського ПЗ на це може бути витрачено рік і навіть більше.<a href="https://conf.ztu.edu.ua/wp-content/uploads/2022/04/56.pdf" target="_blank" rel="noreferrer">[13]</a></p><p align="center"><img src="https://www.it-courses.by/wp-content/uploads/2022/04/cicd_1_5bb3b8b9d32785bffaa5e9a390d2e894.png" alt="CI/CD"></p><p align="center">Схема CI/CD</p><h2 id="⚖️-порівняльна-характеристика-наявних-засобів-вирішення-завдання" tabindex="-1">⚖️ Порівняльна характеристика наявних засобів вирішення завдання <a class="header-anchor" href="#⚖️-порівняльна-характеристика-наявних-засобів-вирішення-завдання" aria-label="Permalink to &quot;⚖️ Порівняльна характеристика наявних засобів вирішення завдання&quot;">​</a></h2><h3 id="🌍-огляд-сервісів" tabindex="-1">🌍 Огляд сервісів <a class="header-anchor" href="#🌍-огляд-сервісів" aria-label="Permalink to &quot;🌍 Огляд сервісів&quot;">​</a></h3><ul><li><p><a href="https://github.com/features/issues" target="_blank" rel="noreferrer">GitHub Projects</a> — це платформа для спільної роботи над різними проєктами, особливо при розробці програмного забезпечення. В основі GitHub лежить система, яка називається Git, що дозволяє відстежувати зміни у файлах і координувати роботу багатьох людей.</p></li><li><p><a href="https://shelfy.com.ua/programs/asana/" target="_blank" rel="noreferrer">Asana</a> — це потужне та багатофункціональне програмне забезпечення для управління проектами, організації робочих процесів, відстеження прогресу команди та досягнення кращих результатів</p></li><li><p><a href="https://hostiq.ua/blog/ukr/what-is-trello-2/" target="_blank" rel="noreferrer">Trello</a> — це онлайн-платформа для управління проєктами та завданнями. Trello підходить для контролю роботи в невеликих компаніях та стартапах. Ця система організована за принципом канбан — популярною методикою управління проєктами.</p></li><li><p><a href="https://vchymo.com/app/application/Miro" target="_blank" rel="noreferrer">Miro</a> — платформа для спільної віддаленої роботи за допомогою онлайн-дошки. Дошка підходить для складання проектів, креативу, дизайн-концепцій, брейнстормінгу та освітніх цілей. Спільна робота Miro здійснюється за допомогою текстового, голосового або відеочата, а також спільного наповнення та перегляду дошки в реальному часі.</p></li><li><p><a href="https://www.fortsoft.com.ua/ua/catalog/upravleniye-proyektami-zadachami/atlassian-jira-software.html?srsltid=AfmBOorBbRz9_kWx0g2Dl-GH1hzZ-K5LDEeEH-LCKddN0jPwnXIQ2FNo" target="_blank" rel="noreferrer">Jira</a> — це засіб адміністрування проектів agile-команд, розроблений таким чином, щоб розробники могли планувати, виправляти та випускати якісні продукти.</p></li><li><p><a href="https://icoola.ua/blog/programa-notion-na-iphone/?srsltid=AfmBOoqKsvkZQZXaH49FdpWLeVN-5MEwr7Q_oeg-4DGLzgdMf_WYdKjh" target="_blank" rel="noreferrer">Notion</a> — це універсальний додаток для організації, який поєднує таблиці, списки, бази даних та дошки в одному просторі, що дозволяє легко керувати завданнями та проектами на iPhone і Mac. З його допомогою можна зберігати текстові документи, відео та зображення, а також синхронізувати дані між пристроями для ефективної роботи і планування.</p></li><li><p><a href="https://uk.wikipedia.org/wiki/Basecamp" target="_blank" rel="noreferrer">Basecamp</a> — інструмент для управління проєктами, який розповсюджується по публічно-хмарній моделі. Використовується для командної роботи над проєктами та задачами. Все спілкування відбувається у вигляді блогу, завдання ставляться як to-do списки, що зручно тільки в разі якихось загальних описів для розвитку проєкту. Також немає можливості складати звіти.</p></li></ul><h3 id="📊-порівняльна-таблиця" tabindex="-1">📊 Порівняльна таблиця <a class="header-anchor" href="#📊-порівняльна-таблиця" aria-label="Permalink to &quot;📊 Порівняльна таблиця&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Сервіс</th><th>Основні можливості</th><th>Тип управління</th><th>Інтеграції</th><th>Особливості</th><th>Недоліки</th></tr></thead><tbody><tr><td><strong>GitHub Projects</strong></td><td>Управління задачами, Kanban-дошка, відстеження змін у коді</td><td>Kanban, Agile</td><td>GitHub, CI/CD, Slack</td><td>Глибока інтеграція з GitHub</td><td>Не підходить для нетехнічних команд</td></tr><tr><td><strong>Asana</strong></td><td>Управління задачами, проєктами, таймлайн, пріоритети</td><td>Agile, Scrum</td><td>Slack, Google Drive, Zoom</td><td>Гнучкість у керуванні задачами</td><td>Висока вартість преміум-функцій</td></tr><tr><td><strong>Trello</strong></td><td>Kanban-дошка, чек-листи, теги, автоматизація</td><td>Kanban</td><td>Google Drive, Slack, Jira</td><td>Простий інтерфейс, гнучкість</td><td>Обмежений функціонал у безкоштовній версії</td></tr><tr><td><strong>Miro</strong></td><td>Візуальні дошки, брейнштормінг, діаграми</td><td>Гнучке управління</td><td>Slack, Zoom, Notion</td><td>Інтерактивна колаборація</td><td>Важко керувати великими проєктами</td></tr><tr><td><strong>Jira</strong></td><td>Відстеження задач, Agile-борди, спринти</td><td>Scrum, Kanban</td><td>Bitbucket, Confluence, Slack</td><td>Підходить для складних проєктів</td><td>Висока складність для початківців</td></tr><tr><td><strong>Notion</strong></td><td>Нотатки, бази даних, Kanban-дошки, управління знаннями</td><td>Гнучке управління</td><td>Slack, Google Drive, API</td><td>Універсальний робочий простір</td><td>Не підходить для складних проєктів</td></tr><tr><td><strong>Basecamp</strong></td><td>Управління проєктами, повідомлення, файли</td><td>Гнучке управління</td><td>Email, календарі</td><td>Простий у використанні</td><td>Обмежена гнучкість у завданнях</td></tr></tbody></table><h2 id="🎯-висновки" tabindex="-1">🎯 Висновки <a class="header-anchor" href="#🎯-висновки" aria-label="Permalink to &quot;🎯 Висновки&quot;">​</a></h2><p>Проаналізувавши деякі застосунки й веб-сервіси, які пропонують засоби для управління проєктами, можемо підсумувати, що кожна система має переваги й недоліки, відштовхуючись від яких користувач обирає ідеальний варіант для себе. Жодна з розглянутих платформ не пропонує оффлайн-доступ, що значно знижує рівень комфорту використання. Також серед мінусів занадто великий вибір функцій, що часто плутає користувача і ускладнює оптимізацію роботи.</p><p>Зважаючи на зібрану інформацію, можемо зробити висновок: важливим є створення такого сервісу, який запропонує необхідіний користувачеві функціонал, при цьому забезпечить ефективне управління робочими задачами і збереже баланс між широтою інструментів і інтуїтивно зрозумілим інтерфейсом.</p><h2 id="🔗-посилання" tabindex="-1">🔗 Посилання <a class="header-anchor" href="#🔗-посилання" aria-label="Permalink to &quot;🔗 Посилання&quot;">​</a></h2><ol><li><a href="https://uk.wikipedia.org/wiki/%D0%9F%D1%80%D0%BE%D1%94%D0%BA%D1%82" target="_blank" rel="noreferrer">Проєкт</a></li><li><a href="https://pmb.com.ua/uk/slovar-terminov/sistema-upravleniya-proektom-project-management-system-instrument/" target="_blank" rel="noreferrer">Система управління проектами</a></li><li><a href="https://pmb.com.ua/uk/slovar-terminov/zhiznennyj-tsikl-proekta-project-life-cycle/" target="_blank" rel="noreferrer">Життєвий цикл проєкту</a></li><li><a href="https://dtkt.ua/dictionary/p/7447-programne-zabezpecennya" target="_blank" rel="noreferrer">Програмне забезпечення</a></li><li><a href="https://qalearning.com.ua/theory/lectures/material/requirements-testing-methods-equivalence/" target="_blank" rel="noreferrer">Вимоги до програмного забезпечення</a></li><li><a href="https://uk.wikipedia.org/wiki/%D0%90%D1%80%D1%82%D0%B5%D1%84%D0%B0%D0%BA%D1%82_(UML)" target="_blank" rel="noreferrer">Артефакт</a></li><li><a href="https://worksection.com/ua/blog/agile.html" target="_blank" rel="noreferrer">Agile Model</a></li><li><a href="https://career.softserveinc.com/uk-ua/stories/what-is-scrum-methodology" target="_blank" rel="noreferrer">Scrum</a></li><li><a href="https://www.maxzosim.com/boehms-spiral-model/" target="_blank" rel="noreferrer">Spiral Model</a></li><li><a href="https://itwiki.dev/qa/dev-methodologies/incremental-development-model" target="_blank" rel="noreferrer">Incremental Model</a></li><li><a href="https://www.ukraine.com.ua/blog/interesting/chto-takoe-kanban.html" target="_blank" rel="noreferrer">Kanban</a></li><li><a href="https://web-promo.ua/ua/blog/kanban-sho-ce-take-i-chim-vin-bude-korisnim-marketologam/" target="_blank" rel="noreferrer">Kanban-board</a></li></ol>',97),o=[n];function i(p,s,h,d,c,m){return r(),a("div",null,o)}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
